create or replace function public.create_appointment_v2(p_doctor_id uuid, p_slot_id uuid, p_complaint_note text default null) returns jsonb language plpgsql as $function$ declare v_slot_booked boolean; v_fee numeric(12,2); v_appointment_id uuid; v_patient_id uuid; begin select is_booked into v_slot_booked from public.doctor_slots where id = p_slot_id; if not found then raise exception 'SLOT_NOT_FOUND'; end if; if v_slot_booked then raise exception 'SLOT_ALREADY_BOOKED'; end if; select id into v_patient_id from public.user_profiles where auth_id = auth.uid(); if not found then raise exception 'USER_PROFILE_NOT_FOUND'; end if; select consultation_fee into v_fee from public.doctors where id = p_doctor_id; if not found then raise exception 'DOCTOR_NOT_FOUND'; end if; insert into public.appointments (patient_id, doctor_id, slot_id, consultation_fee_snapshot, complaint_note) values (v_patient_id, p_doctor_id, p_slot_id, v_fee, p_complaint_note) returning id into v_appointment_id; return jsonb_build_object('appointment_id', v_appointment_id::text); end; $function$;